import{_ as e,o,c as d,a0 as a}from"./chunks/framework.CWk8AOcY.js";const b=JSON.parse('{"title":"节点与运行时配置文件路径与说明","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/ops-manual/03-node-runtime-config.md","filePath":"zh/guide/ops-manual/03-node-runtime-config.md"}'),c={name:"zh/guide/ops-manual/03-node-runtime-config.md"};function i(r,t,l,n,s,h){return o(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="节点与运行时配置文件路径与说明" tabindex="-1">节点与运行时配置文件路径与说明 <a class="header-anchor" href="#节点与运行时配置文件路径与说明" aria-label="Permalink to &quot;节点与运行时配置文件路径与说明&quot;">​</a></h1><p>本章覆盖运行 sandbox 必须维护的节点侧组件：</p><ul><li><code>Cubelet</code></li><li><code>Cubelet/dynamicconf</code></li><li><code>network-agent</code></li><li><code>CubeShim</code></li><li><code>cube-runtime</code></li><li>guest kernel / guest image / VM socket / snapshot 路径</li></ul><h2 id="_1-cubelet-静态配置-config-toml" tabindex="-1">1. Cubelet 静态配置 <code>config.toml</code> <a class="header-anchor" href="#_1-cubelet-静态配置-config-toml" aria-label="Permalink to &quot;1. Cubelet 静态配置 `config.toml`&quot;">​</a></h2><h3 id="_1-1-路径" tabindex="-1">1.1 路径 <a class="header-anchor" href="#_1-1-路径" aria-label="Permalink to &quot;1.1 路径&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>路径</th></tr></thead><tbody><tr><td>仓库源文件</td><td><code>Cubelet/config/config.toml</code></td></tr><tr><td>安装后生效</td><td><code>/usr/local/services/cubetoolbox/Cubelet/config/config.toml</code></td></tr></tbody></table><p>启动方式：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cubelet</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/services/cubetoolbox/Cubelet/config/config.toml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --dynamic-conf-path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/services/cubetoolbox/Cubelet/dynamicconf/conf.yaml</span></span></code></pre></div><h3 id="_1-2-文件头部与全局路径" tabindex="-1">1.2 文件头部与全局路径 <a class="header-anchor" href="#_1-2-文件头部与全局路径" aria-label="Permalink to &quot;1.2 文件头部与全局路径&quot;">​</a></h3><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td><code>root = &quot;/data/cubelet/root&quot;</code></td><td>containerd / overlayfs 数据根目录</td></tr><tr><td><code>state = &quot;/data/cubelet/state&quot;</code></td><td>元数据与状态目录</td></tr><tr><td><code>pid_file = &quot;/run/cube-let.pid&quot;</code></td><td>pid 文件</td></tr><tr><td><code>dynamic_config_path</code></td><td>指向动态配置 yaml</td></tr></tbody></table><h3 id="_1-3-核心监听项" tabindex="-1">1.3 核心监听项 <a class="header-anchor" href="#_1-3-核心监听项" aria-label="Permalink to &quot;1.3 核心监听项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>配置段</th><th>关键字段</th><th>说明</th></tr></thead><tbody><tr><td><code>[http]</code></td><td><code>address = &quot;:9998&quot;</code></td><td>HTTP 接口</td></tr><tr><td><code>[grpc]</code></td><td><code>address = &quot;/data/cubelet/cubelet.sock&quot;</code>, <code>tcp_address = &quot;:9999&quot;</code></td><td>Unix / TCP gRPC</td></tr><tr><td><code>[cubetap]</code></td><td><code>address = &quot;/data/cubelet/cubetap.sock&quot;</code></td><td>tap 相关 socket</td></tr><tr><td><code>[operation_server]</code></td><td><code>cubelet-operation.sock</code></td><td>运维操作 socket</td></tr><tr><td><code>[debug]</code></td><td><code>address = &quot;:9966&quot;</code></td><td>debug 接口</td></tr></tbody></table><h3 id="_1-4-plugins-重点配置" tabindex="-1">1.4 <code>plugins</code> 重点配置 <a class="header-anchor" href="#_1-4-plugins-重点配置" aria-label="Permalink to &quot;1.4 `plugins` 重点配置&quot;">​</a></h3><h4 id="io-cubelet-internal-v1-shimlog" tabindex="-1"><code>io.cubelet.internal.v1.shimlog</code> <a class="header-anchor" href="#io-cubelet-internal-v1-shimlog" aria-label="Permalink to &quot;`io.cubelet.internal.v1.shimlog`&quot;">​</a></h4><ul><li><code>root_path = &quot;/data/cubelet/shimlog&quot;</code></li><li>存放 shim 日志临时目录</li></ul><h4 id="io-cubelet-internal-v1-cleanup" tabindex="-1"><code>io.cubelet.internal.v1.cleanup</code> <a class="header-anchor" href="#io-cubelet-internal-v1-cleanup" aria-label="Permalink to &quot;`io.cubelet.internal.v1.cleanup`&quot;">​</a></h4><ul><li><code>root_path = &quot;/data/cubelet/cleanup&quot;</code></li><li>清理流程工作目录</li></ul><h4 id="io-cubelet-internal-v1-cgroup" tabindex="-1"><code>io.cubelet.internal.v1.cgroup</code> <a class="header-anchor" href="#io-cubelet-internal-v1-cgroup" aria-label="Permalink to &quot;`io.cubelet.internal.v1.cgroup`&quot;">​</a></h4><p>负责宿主与 VM 的资源开销估算：</p><table tabindex="0"><thead><tr><th>字段</th><th>作用</th></tr></thead><tbody><tr><td><code>pool_size</code>, <code>pool_workers</code></td><td>cgroup 资源池规模</td></tr><tr><td><code>vm_cpu_overhead</code></td><td>VM CPU overhead</td></tr><tr><td><code>vm_memory_overhead_base</code> / <code>vm_memory_overhead_coefficient</code></td><td>VM 内存额外开销</td></tr><tr><td><code>host_cpu_overhead</code>, <code>host_memory_overhead_base</code></td><td>宿主侧开销</td></tr><tr><td><code>vm_snapshot_specs_config</code></td><td>快照规格文件，默认 <code>/usr/local/services/cubetoolbox/cube-snapshot/spec.json</code></td></tr><tr><td><code>snapshot_disk_dir</code></td><td>模板/快照磁盘目录，默认 <code>/data/snapshot_pack/disks</code></td></tr></tbody></table><h4 id="io-cubelet-internal-v1-network" tabindex="-1"><code>io.cubelet.internal.v1.network</code> <a class="header-anchor" href="#io-cubelet-internal-v1-network" aria-label="Permalink to &quot;`io.cubelet.internal.v1.network`&quot;">​</a></h4><p>这是节点网络的主配置来源，也是 <code>network-agent</code> 继承配置的上游。</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>object_dir</code></td><td>CubeVS 网络对象目录，默认 <code>/usr/local/services/cubetoolbox/cube-vs/network</code></td></tr><tr><td><code>eth_name</code></td><td>节点上行网卡名</td></tr><tr><td><code>tap_init_num</code></td><td>预分配 tap 数量</td></tr><tr><td><code>cidr</code></td><td>sandbox IP 地址池</td></tr><tr><td><code>mvm_inner_ip</code> / <code>mvm_gw_dest_ip</code></td><td>guest 内部 IP / 网关</td></tr><tr><td><code>mvm_mac_addr</code> / <code>mvm_gw_mac_addr</code></td><td>guest / gateway MAC</td></tr><tr><td><code>mvm_mtu</code></td><td>guest MTU</td></tr><tr><td><code>default_exposed_ports</code></td><td>默认暴露端口</td></tr><tr><td><code>enable_network_agent</code></td><td>是否启用 network-agent</td></tr><tr><td><code>network_agent_endpoint</code></td><td>network-agent gRPC endpoint</td></tr><tr><td><code>network_agent_tap_socket</code></td><td>network-agent tap socket</td></tr><tr><td><code>redis_conf_path</code></td><td>旧网络事件流配置</td></tr></tbody></table><h4 id="io-cubelet-internal-v1-storage" tabindex="-1"><code>io.cubelet.internal.v1.storage</code> <a class="header-anchor" href="#io-cubelet-internal-v1-storage" aria-label="Permalink to &quot;`io.cubelet.internal.v1.storage`&quot;">​</a></h4><p>本地磁盘池配置：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>data_path = &quot;/data/cubelet/storage&quot;</code></td><td>块文件/磁盘池目录</td></tr><tr><td><code>pool_type = &quot;copy_reflink&quot;</code></td><td>存储池类型</td></tr><tr><td><code>disksize = &quot;400Gi&quot;</code></td><td>默认磁盘规格</td></tr><tr><td><code>snapshot_base_path = &quot;/data/cube-shim/disks&quot;</code></td><td>snapshot 基础目录</td></tr><tr><td><code>snapshot_format_size_list</code></td><td>快照块文件规格</td></tr></tbody></table><h4 id="io-cubelet-internal-v1-images" tabindex="-1"><code>io.cubelet.internal.v1.images</code> <a class="header-anchor" href="#io-cubelet-internal-v1-images" aria-label="Permalink to &quot;`io.cubelet.internal.v1.images`&quot;">​</a></h4><ul><li><code>runtime_type = &quot;io.containerd.cube.v2&quot;</code></li><li>说明镜像相关逻辑默认走 cube runtime 类型</li></ul><h4 id="io-cubelet-internal-v1-cubebox" tabindex="-1"><code>io.cubelet.internal.v1.cubebox</code> <a class="header-anchor" href="#io-cubelet-internal-v1-cubebox" aria-label="Permalink to &quot;`io.cubelet.internal.v1.cubebox`&quot;">​</a></h4><p>这是运行时注册入口：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>default_runtime_name = &quot;cube&quot;</code></td><td>默认 runtime</td></tr><tr><td><code>runtime_type = &quot;io.containerd.cube.rs&quot;</code></td><td>cube runtime 类型</td></tr><tr><td><code>runtime_cfg_path = &quot;/usr/local/services/cubetoolbox/cube-shim/conf/config-cube.toml&quot;</code></td><td>指向 CubeShim 配置文件</td></tr><tr><td><code>cubetool_base_dir</code></td><td><code>/usr/local/services/cubetoolbox</code></td></tr></tbody></table><h4 id="其它值得关注的段" tabindex="-1">其它值得关注的段 <a class="header-anchor" href="#其它值得关注的段" aria-label="Permalink to &quot;其它值得关注的段&quot;">​</a></h4><ul><li><code>io.cubelet.images-service.v1.images-service.image_gc</code>: 镜像 GC 阈值与周期</li><li><code>io.cubelet.internal.v1.gc-service</code>: 全局 GC 周期</li><li><code>io.containerd.snapshotter.v1.overlayfs</code>: overlayfs 元数据和数据目录</li><li><code>io.containerd.metadata.v1.bolt</code>: bolt metadata 根目录</li><li><code>io.cubelet.chi.v1.vsocket-manager.proxyPort = 1032</code>: vsocket 代理端口</li></ul><h2 id="_2-cubelet-动态配置-dynamicconf-conf-yaml" tabindex="-1">2. Cubelet 动态配置 <code>dynamicconf/conf.yaml</code> <a class="header-anchor" href="#_2-cubelet-动态配置-dynamicconf-conf-yaml" aria-label="Permalink to &quot;2. Cubelet 动态配置 `dynamicconf/conf.yaml`&quot;">​</a></h2><h3 id="_2-1-路径" tabindex="-1">2.1 路径 <a class="header-anchor" href="#_2-1-路径" aria-label="Permalink to &quot;2.1 路径&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>路径</th></tr></thead><tbody><tr><td>仓库源文件</td><td><code>Cubelet/dynamicconf/conf.yaml</code></td></tr><tr><td>安装后生效</td><td><code>/usr/local/services/cubetoolbox/Cubelet/dynamicconf/conf.yaml</code></td></tr></tbody></table><h3 id="_2-2-配置段说明" tabindex="-1">2.2 配置段说明 <a class="header-anchor" href="#_2-2-配置段说明" aria-label="Permalink to &quot;2.2 配置段说明&quot;">​</a></h3><h4 id="common" tabindex="-1"><code>common</code> <a class="header-anchor" href="#common" aria-label="Permalink to &quot;`common`&quot;">​</a></h4><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>enable_pf_mode</code></td><td>是否启用 PF 模式</td></tr><tr><td><code>sandbox_exec_cmd_time_out</code></td><td>sandbox 内执行命令超时</td></tr><tr><td><code>enable_sandbox_exec_cmd_before_exist</code></td><td>sandbox 退出前是否执行清理命令</td></tr><tr><td><code>default_dns_servers</code></td><td>guest 默认 DNS</td></tr></tbody></table><h4 id="host" tabindex="-1"><code>host</code> <a class="header-anchor" href="#host" aria-label="Permalink to &quot;`host`&quot;">​</a></h4><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>scheduler_label</code></td><td>节点调度标签</td></tr><tr><td><code>quota.mcpu_limit</code> / <code>mem_limit</code> / <code>mvm_limit</code></td><td>节点资源上限</td></tr><tr><td><code>gc.code_expiration_time</code></td><td>代码/工作目录保留时间</td></tr><tr><td><code>gc.image_expiration_time</code></td><td>镜像保留时间</td></tr></tbody></table><h4 id="meta-server-config" tabindex="-1"><code>meta_server_config</code> <a class="header-anchor" href="#meta-server-config" aria-label="Permalink to &quot;`meta_server_config`&quot;">​</a></h4><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>meta_server_endpoint</code></td><td>控制面元数据服务地址</td></tr><tr><td><code>status_update_frequency</code></td><td>节点状态上报周期</td></tr><tr><td><code>node_status_max_images</code></td><td>节点状态中汇报的最大镜像数</td></tr></tbody></table><p>计算节点安装时，<code>install-compute.sh</code> / <code>up-compute.sh</code> 会重点检查这里的 <code>meta_server_endpoint</code> 是否存在并正确指向控制面。</p><h2 id="_3-network-agent-配置" tabindex="-1">3. network-agent 配置 <a class="header-anchor" href="#_3-network-agent-配置" aria-label="Permalink to &quot;3. network-agent 配置&quot;">​</a></h2><h3 id="_3-1-路径" tabindex="-1">3.1 路径 <a class="header-anchor" href="#_3-1-路径" aria-label="Permalink to &quot;3.1 路径&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>路径</th></tr></thead><tbody><tr><td>仓库模板</td><td><code>configs/single-node/network-agent.yaml</code></td></tr><tr><td>安装后文件</td><td><code>/usr/local/services/cubetoolbox/network-agent/network-agent.yaml</code></td></tr><tr><td>状态目录</td><td><code>/usr/local/services/cubetoolbox/network-agent/state</code></td></tr></tbody></table><h3 id="_3-2-一个重要事实-yaml-不是最终生效源" tabindex="-1">3.2 一个重要事实：YAML 不是最终生效源 <a class="header-anchor" href="#_3-2-一个重要事实-yaml-不是最终生效源" aria-label="Permalink to &quot;3.2 一个重要事实：YAML 不是最终生效源&quot;">​</a></h3><p>虽然安装包会携带 <code>network-agent.yaml</code>，而且 <code>up.sh</code> 会先检查它存在，但当前 one-click 启动命令并<strong>不会</strong>把它作为启动参数传给 <code>network-agent</code>。</p><p>实际启动方式是：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">network-agent</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cubelet-config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/services/cubetoolbox/Cubelet/config/config.toml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --state-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/services/cubetoolbox/network-agent/state</span></span></code></pre></div><p>因此当前 one-click 下，network-agent 的<strong>真实配置优先级</strong>是：</p><ol><li>命令行 flag</li><li><code>--cubelet-config</code> 指向的 <code>Cubelet/config/config.toml</code></li><li>network-agent 代码内默认值</li></ol><p><code>network-agent.yaml</code> 当前更像“打包期保留的配置占位文件”。</p><h3 id="_3-3-network-agent-yaml-当前内容" tabindex="-1">3.3 <code>network-agent.yaml</code> 当前内容 <a class="header-anchor" href="#_3-3-network-agent-yaml-当前内容" aria-label="Permalink to &quot;3.3 `network-agent.yaml` 当前内容&quot;">​</a></h3><p>当前仓库样例只保存基础监听项：</p><ul><li><code>listen</code></li><li><code>health_listen</code></li><li><code>grpc_listen</code></li></ul><p>如果后续文档网站要强化 network-agent 专章，建议明确区分：</p><ul><li><strong>部署包携带的 yaml</strong></li><li><strong>运行时真正生效的 flag/TOML</strong></li></ul><h2 id="_4-cubeshim-与运行时配置-config-cube-toml" tabindex="-1">4. CubeShim 与运行时配置 <code>config-cube.toml</code> <a class="header-anchor" href="#_4-cubeshim-与运行时配置-config-cube-toml" aria-label="Permalink to &quot;4. CubeShim 与运行时配置 `config-cube.toml`&quot;">​</a></h2><h3 id="_4-1-路径" tabindex="-1">4.1 路径 <a class="header-anchor" href="#_4-1-路径" aria-label="Permalink to &quot;4.1 路径&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>路径</th></tr></thead><tbody><tr><td>仓库模板</td><td><code>deploy/one-click/config-cube.toml</code></td></tr><tr><td>安装后生效</td><td><code>/usr/local/services/cubetoolbox/cube-shim/conf/config-cube.toml</code></td></tr></tbody></table><h3 id="_4-2-这个文件的定位" tabindex="-1">4.2 这个文件的定位 <a class="header-anchor" href="#_4-2-这个文件的定位" aria-label="Permalink to &quot;4.2 这个文件的定位&quot;">​</a></h3><p>当前开源版 <code>config-cube.toml</code> 内容非常保守，主要作用是<strong>把运行时资产路径固定为 on-disk contract</strong>。也就是说，它更偏向“路径契约文件”，而不是一个复杂的 tunable runtime config。</p><p>文件中列出的标准资产路径包括：</p><table tabindex="0"><thead><tr><th>资产</th><th>标准路径</th></tr></thead><tbody><tr><td>shim binary</td><td><code>/usr/local/services/cubetoolbox/cube-shim/bin/containerd-shim-cube-rs</code></td></tr><tr><td><code>cube-runtime</code></td><td><code>/usr/local/services/cubetoolbox/cube-shim/bin/cube-runtime</code></td></tr><tr><td>guest kernel</td><td><code>/usr/local/services/cubetoolbox/cube-kernel-scf/vmlinux</code></td></tr><tr><td>guest image</td><td><code>/usr/local/services/cubetoolbox/cube-image/cube-guest-image-cpu.img</code></td></tr></tbody></table><h2 id="_5-cubeshim-代码里的内建默认路径" tabindex="-1">5. CubeShim 代码里的内建默认路径 <a class="header-anchor" href="#_5-cubeshim-代码里的内建默认路径" aria-label="Permalink to &quot;5. CubeShim 代码里的内建默认路径&quot;">​</a></h2><p>很多真正影响运行时行为的路径，并不在 <code>config-cube.toml</code> 里，而是在 <code>CubeShim</code> 源码中写死或从 annotation 推导。</p><h3 id="_5-1-内核与镜像" tabindex="-1">5.1 内核与镜像 <a class="header-anchor" href="#_5-1-内核与镜像" aria-label="Permalink to &quot;5.1 内核与镜像&quot;">​</a></h3><p>源码位置：</p><ul><li><code>CubeShim/shim/src/sandbox/config.rs</code></li><li><code>CubeShim/shim/src/hypervisor/config.rs</code></li></ul><p>对应默认值：</p><table tabindex="0"><thead><tr><th>项目</th><th>默认路径</th></tr></thead><tbody><tr><td>kernel</td><td><code>/usr/local/services/cubetoolbox/cube-kernel-scf/vmlinux</code></td></tr><tr><td>guest image</td><td><code>/usr/local/services/cubetoolbox/cube-image/cube-guest-image-cpu.img</code></td></tr></tbody></table><p>如果请求 annotation 中带了 <code>cube.vm.kernel.path</code>，则可以覆盖默认 kernel。</p><h3 id="_5-2-sandbox-socket-与-vm-目录" tabindex="-1">5.2 sandbox socket 与 VM 目录 <a class="header-anchor" href="#_5-2-sandbox-socket-与-vm-目录" aria-label="Permalink to &quot;5.2 sandbox socket 与 VM 目录&quot;">​</a></h3><p>源码位置：<code>CubeShim/shim/src/common/utils.rs</code></p><table tabindex="0"><thead><tr><th>项目</th><th>默认路径</th></tr></thead><tbody><tr><td>VM 根目录</td><td><code>/run/vc/vm/</code></td></tr><tr><td>sandbox vsock socket</td><td><code>/run/vc/vm/&lt;sandbox-id&gt;/cube.sock</code></td></tr><tr><td>chapi 路径</td><td><code>/run/vc/vm/&lt;sandbox-id&gt;/chapi</code></td></tr></tbody></table><p>这也是 <code>cube-runtime login &lt;sandbox-id&gt;</code> 能工作的基础。</p><h3 id="_5-3-暂停态快照目录" tabindex="-1">5.3 暂停态快照目录 <a class="header-anchor" href="#_5-3-暂停态快照目录" aria-label="Permalink to &quot;5.3 暂停态快照目录&quot;">​</a></h3><p>源码位置：</p><ul><li><code>CubeShim/shim/src/common/mod.rs</code></li><li><code>CubeShim/shim/src/common/utils.rs</code></li></ul><p>默认值：</p><table tabindex="0"><thead><tr><th>项目</th><th>默认路径</th></tr></thead><tbody><tr><td>pause VM snapshot base</td><td><code>/data/cubelet/root/pausevm</code></td></tr></tbody></table><h3 id="_5-4-debug-console-默认端口" tabindex="-1">5.4 debug console 默认端口 <a class="header-anchor" href="#_5-4-debug-console-默认端口" aria-label="Permalink to &quot;5.4 debug console 默认端口&quot;">​</a></h3><p>源码位置：<code>CubeShim/shim/src/hypervisor/config.rs</code></p><p>默认会向 guest 注入：</p><ul><li><code>agent.debug_console</code></li><li><code>agent.debug_console_vport=1026</code></li></ul><p>这就是 <code>cube-runtime login</code> 默认使用 <code>--port 1026</code> 的根源。</p><h2 id="_6-cube-runtime-自身没有独立配置文件" tabindex="-1">6. <code>cube-runtime</code> 自身没有独立配置文件 <a class="header-anchor" href="#_6-cube-runtime-自身没有独立配置文件" aria-label="Permalink to &quot;6. `cube-runtime` 自身没有独立配置文件&quot;">​</a></h2><p><code>cube-runtime</code> 的特点是：</p><ul><li>没有独立 yaml/toml</li><li>通过子命令参数工作</li><li>依赖 CubeShim 的默认路径和当前 sandbox 运行状态</li></ul><h3 id="_6-1-login-依赖项" tabindex="-1">6.1 <code>login</code> 依赖项 <a class="header-anchor" href="#_6-1-login-依赖项" aria-label="Permalink to &quot;6.1 `login` 依赖项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td><code>sandbox-id</code> 存在</td><td>对应目录必须在 <code>/run/vc/vm/</code> 下</td></tr><tr><td><code>cube.sock</code> 存在</td><td>说明 sandbox shim/vsock 可连通</td></tr><tr><td>debug console 端口打开</td><td>默认 <code>1026</code></td></tr></tbody></table><h3 id="_6-2-snapshot-依赖项" tabindex="-1">6.2 <code>snapshot</code> 依赖项 <a class="header-anchor" href="#_6-2-snapshot-依赖项" aria-label="Permalink to &quot;6.2 `snapshot` 依赖项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td><code>--disk</code> / <code>--resource</code> / <code>--pmem</code></td><td>都要传 JSON 字符串</td></tr><tr><td><code>--kernel</code></td><td>传 guest kernel 路径</td></tr><tr><td>目录可写</td><td><code>--path</code> 必须可写</td></tr></tbody></table><p>如果你想从更业务化的角度做模板快照，优先使用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cubecli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cubebox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> snapshot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ...</span></span></code></pre></div><h2 id="_7-节点侧配置排查顺序" tabindex="-1">7. 节点侧配置排查顺序 <a class="header-anchor" href="#_7-节点侧配置排查顺序" aria-label="Permalink to &quot;7. 节点侧配置排查顺序&quot;">​</a></h2><p>出现节点问题时，建议按下面顺序看：</p><ol><li><code>/usr/local/services/cubetoolbox/Cubelet/config/config.toml</code></li><li><code>/usr/local/services/cubetoolbox/Cubelet/dynamicconf/conf.yaml</code></li><li><code>/usr/local/services/cubetoolbox/network-agent/state</code></li><li><code>/usr/local/services/cubetoolbox/cube-shim/conf/config-cube.toml</code></li><li><code>/run/vc/vm/&lt;sandbox-id&gt;/cube.sock</code></li><li><code>/data/cubelet/root</code>、<code>/data/cubelet/state</code>、<code>/data/cubelet/storage</code></li></ol><p>如果问题是“能创建但进不去 guest”，优先检查：</p><ul><li><code>cube-runtime login &lt;sandbox-id&gt;</code></li><li><code>/run/vc/vm/&lt;sandbox-id&gt;/cube.sock</code></li><li><code>agent.debug_console_vport=1026</code> 对应的 guest debug console</li></ul>',102)])])}const m=e(c,[["render",i]]);export{b as __pageData,m as default};
